#!/bin/bash
# HERCOSSNUX NPU - Paso 19: documentacion y publicacion del core #17.
#
# Instala:
#   README.md        13 secciones en ingles, siguiendo el formato del RV32IMA
#   npu_arch.svg     diagrama de arquitectura 760x560, paleta propia del core
#   commit_npu.sh    commit y push a GitLab + GitHub (pide confirmacion)
#
# El README documenta sin omitir nada:
#   - los cinco niveles de verificacion con sus firmas y mutaciones
#   - los siete intentos del DMA y que rompio el bucle (instrumentar el bus
#     AXI, no los registros internos)
#   - el doble driver de err_r resolviendo a 'X'
#   - las memorias con 64 lecturas simultaneas disolviendose en LUT
#   - VHDL-2008 rechazado como top de module reference
#   - la automatizacion del CIPS pidiendo claves indefinidamente
#   - CH0_DDR4_0_BOARD_INTERFACE y el error de metodo que costo seis rondas
#   - la estimacion OOC optimista por tres ordenes de magnitud
#
# La seccion 11 (Future work) recoge las tres vias para recuperar 100 MHz.
#
# El SVG se referencia como fichero, no en linea: GitLab y GitHub renderizan
# el SVG embebido como markup crudo.
(
set -e
DIR="$HOME/vhdl_repo/IP_Cores/NPU"
if [ ! -f "$DIR/rtl/npu_axi_top.vhd" ]; then
  echo "FALLO: falta rtl/npu_axi_top.vhd (corre primero los Pasos 1-18)"; exit 1
fi
base64 -d << "EOF" > "$DIR/README.md"

EOF
base64 -d << "EOF" > "$DIR/npu_arch.svg"

EOF
base64 -d << "EOF" > "$DIR/commit_npu.sh"

EOF
chmod +x "$DIR/commit_npu.sh"
echo "Instalados en $DIR/:"
echo "  README.md      ($(wc -l < "$DIR/README.md") lineas, 13 secciones)"
echo "  npu_arch.svg   (diagrama de arquitectura)"
echo "  commit_npu.sh  (commit y push, pide confirmacion)"
echo ""
echo "Antes de publicar, revisa el README:"
echo "  less $DIR/README.md"
echo ""
echo "Y anade la fila del core #17 a la tabla de $HOME/vhdl_repo/README.md"
echo ""
echo "Para commitear:"
echo "  bash $DIR/commit_npu.sh"
)
